#include <stdio.h>
#include <stdlib.h>
#include <string.h>

int compare(const void *a, const void *b) {
    return (*(int*)a - *(int*)b);
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int n;
        scanf("%d", &n);
        char s[n + 1];
        scanf("%s", s);
        int x[n];
        for (int i = 0; i < n; i++) {
            scanf("%d", &x[i]);
        }
        int villages_with_electricity[n];
        int count = 0;
        for (int i = 0; i < n; i++) {
            if (s[i] == '1') {
                villages_with_electricity[count++] = x[i];
            }
        }
        qsort(villages_with_electricity, count, sizeof(int), compare);
        long long total_length = 0;
        for (int i = 0; i < n; i++) {
            if (s[i] == '0') {
                int min_distance = 1000000000;
                for (int j = 0; j < count; j++) {
                    int distance = abs(x[i] - villages_with_electricity[j]);
                    if (distance < min_distance) {
                        min_distance = distance;
                    }
                }
                total_length += min_distance;
            }
        }
        printf("%lld\n", total_length);
    }
    return 0;
}

