import java.util.Arrays;
import java.util.Scanner;

public class Main {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int T = scanner.nextInt();
        while (T-- > 0) {
            int n = scanner.nextInt();
            String s = scanner.next();
            int[] x = new int[n];
            for (int i = 0; i < n; i++) {
                x[i] = scanner.nextInt();
            }
            int[] villages_with_electricity = new int[n];
            int count = 0;
            for (int i = 0; i < n; i++) {
                if (s.charAt(i) == '1') {
                    villages_with_electricity[count++] = x[i];
                }
            }
            Arrays.sort(villages_with_electricity, 0, count);
            long total_length = 0;
            for (int i = 0; i < n; i++) {
                if (s.charAt(i) == '0') {
                    int min_distance = 1000000000;
                    for (int j = 0; j < count; j++) {
                        int distance = Math.abs(x[i] - villages_with_electricity[j]);
                        if (distance < min_distance) {
                            min_distance = distance;
                        }
                    }
                    total_length += min_distance;
                }
            }
            System.out.println(total_length);
        }
    }
}

